"""matplotlib.markers — marker style definitions."""

import numpy as _np

# All matplotlib marker codes
TICKLEFT, TICKRIGHT, TICKUP, TICKDOWN = range(4)
CARETLEFT, CARETRIGHT, CARETUP, CARETDOWN = range(4, 8)
CARETLEFTBASE, CARETRIGHTBASE, CARETUPBASE, CARETDOWNBASE = range(8, 12)

_marker_map = {
    '.': 'point', ',': 'pixel', 'o': 'circle', 'v': 'triangle_down',
    '^': 'triangle_up', '<': 'triangle_left', '>': 'triangle_right',
    '1': 'tri_down', '2': 'tri_up', '3': 'tri_left', '4': 'tri_right',
    '8': 'octagon', 's': 'square', 'p': 'pentagon', '*': 'star',
    'h': 'hexagon1', 'H': 'hexagon2', '+': 'plus', 'x': 'x',
    'D': 'diamond', 'd': 'thin_diamond', '|': 'vline', '_': 'hline',
    'P': 'plus_filled', 'X': 'x_filled',
    0: 'tickleft', 1: 'tickright', 2: 'tickup', 3: 'tickdown',
    4: 'caretleft', 5: 'caretright', 6: 'caretup', 7: 'caretdown',
    8: 'caretleftbase', 9: 'caretrightbase', 10: 'caretupbase', 11: 'caretdownbase',
    'None': 'nothing', 'none': 'nothing', ' ': 'nothing', '': 'nothing',
}

filled_markers = ('o', 'v', '^', '<', '>', '8', 's', 'p', '*', 'h', 'H', 'D', 'd', 'P', 'X')
fillstyles = ('full', 'left', 'right', 'bottom', 'top', 'none')


class MarkerStyle:
    markers = _marker_map
    filled_markers = filled_markers
    fillstyles = fillstyles

    def __init__(self, marker=None, fillstyle=None):
        self._marker = marker
        self._fillstyle = fillstyle or 'full'

    def get_marker(self): return self._marker
    def set_marker(self, marker): self._marker = marker
    def get_fillstyle(self): return self._fillstyle
    def set_fillstyle(self, fillstyle): self._fillstyle = fillstyle
    def get_path(self): return None
    def get_transform(self): return None
    def is_filled(self): return self._fillstyle != 'none'
    def get_joinstyle(self): return 'round'
    def get_capstyle(self): return 'butt'

    def __bool__(self):
        return self._marker is not None and self._marker not in ('', ' ', 'None', 'none')
